    if (req.body.compact) {
      const keepLast = Math.min(10, session.messages.length);
      const recentMessages = session.messages.slice(-keepLast);
      session.messages = [
        { role: 'user', content: `[之前对话的摘要]\n${result.summary}`, time: new Date() },
