        ...recentMessages
      ];
      session.updatedAt = new Date();
      sessionManager.saveData();
      result.compacted = true;
    }

    res.json(result);
  } catch (error) {
    console.error('总结会话失败:', error);
    res.status(500).json({ error: error.message });
